          jsonb_build_object('entity', 'hr://absence', 'label', 'hr.rel_absences', 'filter', 'employee_id={id}'),
          jsonb_build_object('entity', 'hr://timesheet', 'label', 'hr.rel_timesheets', 'filter', 'employee_id={id}')
