CREATE OR REPLACE FUNCTION hr.get_employee_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_emp hr.employee;
  v_body text;
  v_title text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_emp FROM hr.employee WHERE id = p_id;
    IF NOT FOUND THEN
      RETURN pgv.alert('Salarié introuvable.', 'danger');
    END IF;
    v_title := 'Modifier ' || v_emp.prenom || ' ' || v_emp.nom;
  ELSE
    v_title := 'Nouveau salarié';
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY['Salariés', pgv.call_ref('get_index'), v_title]);

  v_body := v_body || pgv.form('post_employee_save',
    hr._employee_form_body(v_emp)
    || pgv.link_button(pgv.call_ref('get_index'), 'Annuler', 'secondary'),
    'Enregistrer');

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION hr.get_employee_form(integer) IS 'Employee create/edit form';

CREATE OR REPLACE FUNCTION hr.get_registre(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  v_total int;
  r record;
BEGIN
  v_rows := ARRAY[]::text[];

  FOR r IN
    SELECT e.matricule, e.nom, e.prenom,
           CASE e.sexe WHEN 'M' THEN 'Homme' WHEN 'F' THEN 'Femme' ELSE '—' END AS sexe,
           COALESCE(NULLIF(e.nationalite, ''), '—') AS nationalite,
           CASE WHEN e.date_naissance IS NOT NULL THEN to_char(e.date_naissance, 'DD/MM/YYYY') ELSE '—' END AS date_naissance,
           COALESCE(NULLIF(e.poste, ''), '—') AS emploi,
           COALESCE(NULLIF(e.qualification, ''), '—') AS qualification,
           hr.contrat_label(e.type_contrat) AS contrat,
           to_char(e.date_embauche, 'DD/MM/YYYY') AS date_entree,
           CASE WHEN e.date_fin IS NOT NULL THEN to_char(e.date_fin, 'DD/MM/YYYY') ELSE '—' END AS date_sortie,
           pgv.badge(upper(e.statut), hr.statut_variant(e.statut)) AS statut,
           e.id
      FROM hr.employee e
     ORDER BY e.date_embauche, e.nom, e.prenom
  LOOP
    v_rows := v_rows || ARRAY[
      COALESCE(NULLIF(r.matricule, ''), '—'),
      format('<a href="%s">%s %s</a>', pgv.call_ref('get_employee', jsonb_build_object('p_id', r.id)), pgv.esc(r.nom), pgv.esc(r.prenom)),
      r.sexe,
      r.nationalite,
      r.date_naissance,
      r.emploi,
      r.qualification,
      r.contrat,
      r.date_entree,
      r.date_sortie,
      r.statut
    ];
  END LOOP;

  SELECT count(*)::int INTO v_total FROM hr.employee;

  IF v_total = 0 THEN
    v_body := pgv.empty('Aucun salarié enregistré.');
  ELSE
    v_body := '<p><small>Registre unique du personnel — Art. L1221-13 du Code du travail. ' || v_total || ' salarié(s).</small></p>'
      || pgv.md_table(
        ARRAY['Matricule', 'Nom Prénom', 'Sexe', 'Nationalité', 'Naissance', 'Emploi', 'Qualification', 'Contrat', 'Entrée', 'Sortie', 'Statut'],
        v_rows,
        20
      );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION hr.get_registre(jsonb) IS 'Registre unique du personnel — vue légale chronologique (Art. L1221-13)';

CREATE OR REPLACE FUNCTION hr.get_timesheet(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_semaine text;
  v_dept text;
  v_rows text[];
  v_body text;
  v_total_semaine numeric;
  v_nb_salaries int;
  v_date_debut date;
  v_date_fin date;
  r record;
BEGIN
  v_semaine := NULLIF(trim(COALESCE(p_params->>'semaine', '')), '');
  v_dept := NULLIF(trim(COALESCE(p_params->>'dept', '')), '');

  -- Default to current week
  IF v_semaine IS NOT NULL THEN
    v_date_debut := v_semaine::date;
  ELSE
    v_date_debut := date_trunc('week', CURRENT_DATE)::date;
  END IF;
  v_date_fin := v_date_debut + 6;

  -- Stats
  SELECT COALESCE(sum(t.heures), 0), count(DISTINCT t.employee_id)::int
    INTO v_total_semaine, v_nb_salaries
    FROM hr.timesheet t
    JOIN hr.employee e ON e.id = t.employee_id
   WHERE t.date_travail BETWEEN v_date_debut AND v_date_fin
     AND (v_dept IS NULL OR e.departement ILIKE '%' || v_dept || '%');

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Semaine du', to_char(v_date_debut, 'DD/MM/YYYY')),
    pgv.stat('Total heures', v_total_semaine::text || 'h'),
    pgv.stat('Salariés', v_nb_salaries::text)
  ]);

  -- Filters
  v_body := v_body || '<form><div class="grid">'
    || pgv.input('semaine', 'date', 'Début de semaine', to_char(v_date_debut, 'YYYY-MM-DD'))
    || pgv.input('dept', 'text', 'Département', v_dept)
    || '</div><button type="submit" class="secondary">Filtrer</button></form>';

  -- Per-employee summary for the week
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT e.id, e.nom, e.prenom, e.departement, e.heures_hebdo,
           COALESCE(sum(t.heures), 0) AS total
      FROM hr.employee e
      LEFT JOIN hr.timesheet t ON t.employee_id = e.id
           AND t.date_travail BETWEEN v_date_debut AND v_date_fin
     WHERE e.statut = 'actif'
       AND (v_dept IS NULL OR e.departement ILIKE '%' || v_dept || '%')
     GROUP BY e.id, e.nom, e.prenom, e.departement, e.heures_hebdo
     ORDER BY e.nom, e.prenom
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s %s</a>', pgv.call_ref('get_employee', jsonb_build_object('p_id', r.id)), pgv.esc(r.nom), pgv.esc(r.prenom)),
      COALESCE(NULLIF(r.departement, ''), '—'),
      r.total::text || 'h',
      r.heures_hebdo::text || 'h',
      CASE WHEN r.total >= r.heures_hebdo THEN pgv.badge('OK', 'success')
           WHEN r.total > 0 THEN pgv.badge('Partiel', 'warning')
           ELSE pgv.badge('Vide', 'default') END
    ];
  END LOOP;

  IF cardinality(v_rows) = 0 THEN
    v_body := v_body || pgv.empty('Aucun salarié actif.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Salarié', 'Département', 'Heures', 'Objectif', 'Statut'],
      v_rows,
      20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION hr.get_timesheet(jsonb) IS 'Weekly timesheet overview — per-employee hours summary';

